from decimal import Decimal

from billing.currency import normalize_currency
from billing.ledger import decode_charge
from billing.wire import encode_charge


def test_common_decimal_amount_round_trips():
    payload = encode_charge("ch_17", Decimal("19.5"))
    assert decode_charge(payload) == {
        "charge_id": "ch_17",
        "amount": Decimal("19.5"),
    }


def test_currency_codes_are_normalized():
    assert normalize_currency(" usd ") == "USD"
